import React, { useEffect, useState } from "react";
import axios from "axios";
import Swal from "sweetalert2";
import { useParams, useNavigate } from "react-router-dom";

function ProductDetail()
{
    const navigate = useNavigate();
    const { category_slug, product_slug } = useParams();
    const [loading, setLoading] = useState(true);
    const [product, setProduct] = useState({});
    const [category, setCategory] = useState({});

    useEffect(() =>
    {
        let isMounted = true;

        axios.get(`/api/view-product-detail/${category_slug}/${product_slug}`).then(res =>
        {
            if (isMounted)
            {
                if (res.data.status === 200)
                {
                    setProduct(res.data.product);
                    setCategory(res.data.category);

                } else if (res.data.status === 404)
                {
                    navigate('/collections');
                    Swal.fire("Warning", res.data.message, "error");
                }
                setLoading(false);
            }
        }).catch(err =>
        {
            if (isMounted)
            {
                console.error("Error fetching product details:", err);
                Swal.fire("Error", "Could not fetch data. Please try again later.", "error");
                setLoading(false);
            }
        });

        return () =>
        {
            isMounted = false;
        };
    }, [category_slug, product_slug, navigate]);




    if (loading)
    {
        return <h4>Loading Product Details...</h4>;
    }
    else
    {
        var showProductDetails = '';
        if (product)
        {
            showProductDetails = <div className="py-3">
                <div className="container">
                    <div className="row">

                        <div className="col-md-4 border-end">
                            <img src={`http://127.0.0.1:8000/${product.image}`} alt={product.name} className="w-100" />
                        </div>

                        <div className="col-md-8">
                            <h4>
                                {product.name}
                                <span className="float-end badge btn-sm btn-danger badge-pill">{product.brand}</span>
                            </h4>
                            <p>{product.description}</p>
                            <h4 className="mb-1">
                                KSH: {product.selling_price}
                                <s className="ms-2"> KSH: {product.original_price} </s>
                            </h4>

                            <button type="button" className="btn btn-danger mt-3">Add to Wishlist</button>

                        </div>

                    </div>
                </div>
            </div>;
        }
        else
        {
            showProductDetails = <div className="col-md-12">
                <h4>No Product Details Available</h4>
            </div>
        }
    }

    return (
        <div>
            <div className="py-3 bg-warning">
                <div className="container">
                    <h6>Collections / {category.name} / {product.name}</h6>
                </div>
            </div>
            {showProductDetails}
        </div>
    );

}

export default ProductDetail;
